import React, { useEffect } from "react";
import "./Home.css";
import { MdLocalPhone } from "react-icons/md";
import Aos from "aos";
import "aos/dist/aos.css";
import { Swiper, SwiperSlide } from "swiper/react";
import "swiper/css";
import "swiper/css/effect-fade";
import "swiper/css/navigation";
import "swiper/css/pagination";
import { useQuery } from "@tanstack/react-query";
import Loading from "../Loading/Loading.jsx";
import { Autoplay, EffectFade } from "swiper/modules";



function Home() {
  const { data, isLoading, isSuccess, error } = useQuery({
    queryKey: ["home"],
    queryFn: () => fetch("http://127.0.0.1:8000/api/Home").then((res) => res.json()),
  });

  function scrollToElement() {
    const targetElement = document.getElementById("main");
    if (targetElement) {
      targetElement.scrollIntoView({ behavior: "smooth" });
    }
  }

  return (
    <>
   
      {isLoading && <Loading />}
      {isSuccess && <> <Swiper
        className="home-swiper"
        autoplay={{
          delay: 3000,
        }}
        effect="fade"
        modules={[EffectFade, Autoplay]}
        loop={true}
      > {data.map((item) => (

        <SwiperSlide className="home-swiper-slide">
          <img src={item.home_image} alt={item.home_image} />
          <div className="slide-text">{item.home_title}</div>
        </SwiperSlide>

))}</Swiper><div className="scrollDown" onClick={scrollToElement}>
<span></span>
<span></span>
<span></span>
</div></>}
      {error && <p>Error: {error.message}</p>}
      
    </>
  );
}

export default Home;




